import React, {useState} from 'react';
import api from '../services/api';
import './Signup.css';

const fields = [
  {name:'firstName', label:'First name', type:'text'},
  {name:'lastName', label:'Last name', type:'text'},
  {name:'email', label:'Email', type:'email'},
  {name:'mobileNumber', label:'Mobile number', type:'tel'},
  {name:'username', label:'Username', type:'text'},
  {name:'password', label:'Password', type:'password'},
];

export default function Signup(){
  const initialState = fields.reduce((acc, field) => ({...acc, [field.name]: ''}), {});
  const [form, setForm] = useState(initialState);
  const [msg, setMsg] = useState(null);
  const [submitting, setSubmitting] = useState(false);

  const onChange = e => setForm({...form, [e.target.name]: e.target.value});

  const onSubmit = async e => {
    e.preventDefault();
    setSubmitting(true);
    setMsg(null);
    try{
      const res = await api.post('/auth/register', form);
      setMsg({type:'success', text: res.data.message});
      setForm(initialState);
    }catch(err){
      const text = err?.response?.data?.error || 'Registration failed';
      setMsg({type:'error', text});
    }finally{
      setSubmitting(false);
    }
  };

  return (
    <div className="signup-page">
      <div className="signup-card">
        <div className="signup-card__header">
          <h2>Create your account</h2>
          <p>Join Alok’s & Brothers to manage inventory, orders, and clients from one dashboard.</p>
        </div>
        <div className="signup-card__body">
          {msg && <div className={`signup-message ${msg.type}`}>{msg.text}</div>}
          <form className="signup-form" onSubmit={onSubmit}>
            {fields.map(field => (
              <div key={field.name} className="field-group">
                <input
                  className="field-input"
                  id={field.name}
                  name={field.name}
                  type={field.type}
                  value={form[field.name]}
                  onChange={onChange}
                  placeholder=" "
                  required
                />
                <label className="field-label" htmlFor={field.name}>{field.label}</label>
              </div>
            ))}
            <div className="submit-row">
              <button className="submit-btn" type="submit" disabled={submitting}>
                {submitting ? 'Creating account...' : 'Create account'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
